ValidationRule.errorConditionFormula:
AND(
    NOT(
        OR(
            AND(
                NOT(ISBLANK(TEXT( InquiryType2__c ))),
                NOT(ISBLANK( Date2__c )),
                LEN ( URL2__c ) > 0
            ),
            AND(
                ISBLANK(TEXT( InquiryType2__c )),
                ISBLANK( Date2__c ),
                LEN ( URL2__c ) = 0
            )
        )
    ),
    NOT(
        OR(
            $Profile.Name = 'システム管理者',
            $Profile.Name = 'データ移行管理者'
        )
    )
)
